.panel {
  position: relative;
  display: grid;
  grid-template-rows: auto 1fr auto;
  width: 100%;
  height: 100%;
  min-width: 0;
  min-height: 0;
  background:
    radial-gradient(circle at top, rgba(255, 255, 255, 0.6), rgba(243, 243, 240, 0.9)),
    linear-gradient(180deg, #F3F3F0, #EAEAE7);
  border-left: 1px solid var(--color-border);
}

.header {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  align-items: start;
  gap: 10px;
  padding: 12px 14px 10px;
  border-bottom: 1px solid var(--color-divider);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.4), rgba(243, 243, 240, 0.2));
}

.titleGroup {
  display: flex;
  flex-direction: column;
  gap: 3px;
  min-width: 0;
}

.eyebrow {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--color-text-secondary);
}

.title {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.actions {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  flex-wrap: wrap;
  gap: 8px;
  width: 100%;
  min-width: 0;
}

.modeToggle {
  display: inline-flex;
  align-items: center;
  flex: 0 0 auto;
  padding: 2px;
  border: 1px solid var(--color-border);
