  flex-direction: column;
  align-items: flex-start;
  justify-content: flex-end;
  gap: 6px;
  padding: 14px;
  border-radius: var(--radius-md);
  background: linear-gradient(180deg, rgba(243, 243, 240, 0.08), rgba(243, 243, 240, 0.60));
  pointer-events: none;
}

.emptyTitle {
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--color-text-secondary);
}

.emptyBody {
  max-width: 220px;
  font-size: 12px;
  line-height: 1.5;
  color: var(--color-text-primary);
}

.footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  padding: 10px 14px 12px;
  border-top: 1px solid rgba(0, 0, 0, 0.05);
  font-size: 11px;
  color: var(--color-text-secondary);
  background: linear-gradient(180deg, rgba(243, 243, 240, 0.2), rgba(243, 243, 240, 0.5));
