 3→export function createSheetRevision(options = {}) {
 4→  return {
 5→    id: generateId('revision'),
 6→    code: options.code ?? '',
 7→    date: options.date ?? '',
 8→    description: options.description ?? '',
 9→  };
10→}
11→
12→export function createSheet(title = 'Sheet 1', options = {}) {
13→  return {
14→    id: generateId('sheet'),
15→    title,
16→    paperSize: options.paperSize ?? 'A3_LANDSCAPE',
17→    number: options.number ?? '',
18→    issueDate: options.issueDate ?? '',
19→    scaleLabel: options.scaleLabel ?? '1:100',
20→    scaleMode: options.scaleMode ?? 'custom',
21→    layoutTemplate: options.layoutTemplate ?? 'auto',
22→    drawingName: options.drawingName ?? title,
23→    projectNameOverride: options.projectNameOverride ?? '',
24→    titleBlock: {
25→      projectTitleOverride: options.titleBlock?.projectTitleOverride ?? '',
26→      projectAddressOverride: options.titleBlock?.projectAddressOverride ?? '',
27→      drawnBy: options.titleBlock?.drawnBy ?? '',
28→      checkedBy: options.titleBlock?.checkedBy ?? '',
29→    },
30→    revisions: (options.revisions || []).map((revision) => ({
31→      ...createSheetRevision(),
32→      ...revision,
33→    })),
34→    viewports: (options.viewports || []).map((viewport) => ({ ...viewport })),
35→  };
36→}
37→
38→export function createSheetViewport(sourceView = 'plan', sourceFloorId = null, options = {}) {
39→  const defaultRole = sourceView === '3d_preview'
40→    ? 'supplemental'
41→    : ((sourceView === 'plan' || sourceView === 'roof_plan' || sourceView === 'roof_drainage' || sourceView === 'truss_plan')
42→      ? 'primary'
43→      : (sourceView === 'truss_detail' ? 'detail' : 'secondary'));
44→
45→  return {
46→    id: generateId('viewport'),
47→    sourceView,
48→    sourceFloorId,
49→    sourceRefId: options.sourceRefId ?? null,
50→    x: options.x ?? 20,
51→    y: options.y ?? 20,
52→    width: options.width ?? 160,
53→    height: options.height ?? 100,
54→    scale: options.scale ?? 100,
55→    title: options.title ?? '',
56→    rotation: options.rotation ?? 0,
57→    role: options.role ?? defaultRole,
58→    captionPosition: options.captionPosition ?? 'below',
59→    referenceNote: options.referenceNote ?? '',
60→    lockAutoLayout: options.lockAutoLayout ?? false,
61→    phaseId: options.phaseId ?? null,
62→    phaseViewMode: options.phaseViewMode ?? 'all',
63→  };
64→}
65→
66→export function getSheetDisplayLabel(sheet, index = 0) {
67→  const title = sheet?.title?.trim();
68→  return title || `Sheet ${index + 1}`;
69→}
70→
71→export function getSheetNumberLabel(sheet, index = 0) {
72→  const number = sheet?.number?.trim();
73→  return number || `A${String(index + 1).padStart(2, '0')}`;
74→}
