 25→function ViewportCaption({ viewport }) {
 26→  const isAbove = viewport.caption.position === 'above';
 27→  const ruleY = isAbove ? viewport.y - 2.2 : viewport.y + viewport.height + 1.2;
 28→  const secondaryY = isAbove ? viewport.y - 2.8 : viewport.caption.y;
 29→  const primaryY = secondaryY - 3.1;
 30→
 31→  return (
 32→    <g className="sheet-viewport-caption" pointerEvents="none">
 33→      <line
 34→        x1={viewport.x}
 35→        y1={ruleY}
 36→        x2={viewport.x + viewport.width}
 37→        y2={ruleY}
 38→        stroke={SHEET_COLORS.border}
 39→        strokeWidth={0.3}
 40→      />
 41→      <text
 42→        x={viewport.x}
 43→        y={primaryY}
 44→        fontSize={3}
 45→        fill={SHEET_COLORS.text}
 46→        fontWeight={600}
 47→        letterSpacing={0.12}
 48→      >
 49→        {viewport.caption.primaryText}
 50→      </text>
 51→      <text
 52→        x={viewport.x}
 53→        y={secondaryY}
 54→        fontSize={1.9}
 55→        fill={SHEET_COLORS.textMuted}
 56→        letterSpacing={0.12}
 57→      >
 58→        {viewport.caption.secondaryText}
 59→      </text>
 60→    </g>
 61→  );
 62→}
