 258→    const width = Number(element.getAttribute('width')) || 0;
 259→    const height = Number(element.getAttribute('height')) || 0;
 260→    const viewBox = parseViewBox(element);
 261→    const scaleX = viewBox.width ? width / viewBox.width : 1;
 262→    const scaleY = viewBox.height ? height / viewBox.height : 1;
 263→    matrix = matrix
 264→      .translate(x, y)
 265→      .scale(scaleX || 1, scaleY || 1)
 266→      .translate(-viewBox.minX, -viewBox.minY);
