  1→import { useCallback, useEffect, useMemo, useRef } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { MAX_ZOOM, MIN_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  5→import { fitViewportToSheet } from '@/sheets/layout';
  6→import { SHEET_TOKENS } from '@/sheets/standards';
  7→import { hitTestViewport, hitTestViewportHandle, hitTestViewportRotationHandle } from '@/sheets/hitTest';
  8→import { buildSheetScene } from '@/sheets/layout';
  9→import styles from './SvgCanvas.module.css';
 10→import SheetRenderer from './SheetRenderer';
 11→
 12→function screenToSheet(screenX, screenY, viewport, svgRect) {
 13→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 14→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 15→  return { x, y };
 16→}
 17→
 18→export default function SheetCanvas() {
 19→  const svgRef = useRef(null);
 20→  const dragState = useRef(null);
 21→  const activePointerId = useRef(null);
 22→  const isPanning = useRef(false);
 23→  const lastPanPos = useRef({ x: 0, y: 0 });
 24→
 25→  const { project, dispatch } = useProject();
 26→  const {
 27→    activeSheetId,
 28→    selectedId,
 29→    selectedType,
 30→    viewport,
 31→    dispatch: editorDispatch,
 32→  } = useEditor();
 33→
 34→  const sheet = (project.sheets || []).find((entry) => entry.id === activeSheetId) || null;
 35→  const scene = useMemo(() => buildSheetScene(project, sheet), [project, sheet]);
 36→
 37→  const getSheetPos = useCallback((event) => {
 38→    const rect = svgRef.current.getBoundingClientRect();
 39→    return screenToSheet(event.clientX, event.clientY, viewport, rect);
 40→  }, [viewport]);
 41→
 42→  const updateViewport = useCallback((viewportId, updates) => {
 43→    if (!sheet) return;
 44→    const current = (sheet.viewports || []).find((entry) => entry.id === viewportId);
 45→    if (!current) return;
 46→    const sceneViewport = scene?.viewports.find((entry) => entry.id === viewportId) || null;
 47→    const isManualEdit = ['x', 'y', 'width', 'height', 'rotation'].some((key) => key in updates);
 48→    const baseViewport = sceneViewport
 49→      ? {
 50→          ...current,
 51→          x: sceneViewport.x,
 52→          y: sceneViewport.y,
 53→          width: sceneViewport.width,
 54→          height: sceneViewport.height,
 55→          rotation: sceneViewport.rotation,
 56→        }
 57→      : current;
 58→    const nextViewport = fitViewportToSheet({
 59→      ...baseViewport,
 60→      ...updates,
 61→      lockAutoLayout: 'lockAutoLayout' in updates
 62→        ? updates.lockAutoLayout
 63→        : (isManualEdit ? true : baseViewport.lockAutoLayout),
 64→    }, sheet);
 65→    dispatch({ type: 'SHEET_VIEWPORT_UPDATE', sheetId: sheet.id, viewport: nextViewport });
 66→  }, [dispatch, scene?.viewports, sheet]);
 67→
 68→  const capturePointer = useCallback((pointerId) => {
 69→    if (!svgRef.current) return;
 70→    activePointerId.current = pointerId;
 71→    try {
 72→      svgRef.current.setPointerCapture(pointerId);
 73→    } catch {
 74→      activePointerId.current = pointerId;
 75→    }
 76→  }, []);
 77→
 78→  const releasePointer = useCallback((pointerId = activePointerId.current) => {
 79→    if (!svgRef.current || pointerId == null) {
 80→      activePointerId.current = null;
 81→      return;
 82→    }
 83→    try {
 84→      if (svgRef.current.hasPointerCapture?.(pointerId)) {
 85→        svgRef.current.releasePointerCapture(pointerId);
 86→      }
 87→    } catch {
 88→      // Ignore browsers that reject release calls after capture is already gone.
 89→    }
 90→    activePointerId.current = null;
 91→  }, []);
 92→
 93→  const handlePointerDown = useCallback((event) => {
 94→    if (activePointerId.current !== null && activePointerId.current !== event.pointerId) return;
 95→
 96→    if (event.button === 1 || (event.button === 0 && event.shiftKey)) {
 97→      capturePointer(event.pointerId);
 98→      isPanning.current = true;
 99→      lastPanPos.current = { x: event.clientX, y: event.clientY };
100→      event.preventDefault();
101→      return;
102→    }
103→
104→    if (event.button !== 0) return;
105→
106→    if (!sheet || !scene) return;
107→
108→    const point = getSheetPos(event);
109→
110→    if (selectedType === 'sheetViewport' && selectedId) {
111→      const selectedVp = scene.viewports.find((entry) => entry.id === selectedId);
112→      if (selectedVp && hitTestViewportRotationHandle(point, selectedVp, Math.max(SHEET_TOKENS.viewportHandleSize, 6 / viewport.zoom))) {
113→        const cx = selectedVp.x + selectedVp.width / 2;
114→        const cy = selectedVp.y + selectedVp.height / 2;
115→        dragState.current = {
116→          mode: 'rotate',
117→          viewportId: selectedId,
118→          center: { x: cx, y: cy },
119→          initialRotation: selectedVp.rotation || 0,
120→          startAngle: Math.atan2(point.y - cy, point.x - cx) * (180 / Math.PI),
121→        };
122→        capturePointer(event.pointerId);
123→        event.preventDefault();
124→        return;
125→      }
126→    }
127→
128→    const handleViewportCandidates = selectedType === 'sheetViewport' && selectedId
129→      ? [
130→          ...scene.viewports.filter((entry) => entry.id === selectedId),
131→          ...scene.viewports.filter((entry) => entry.id !== selectedId),
132→        ]
133→      : scene.viewports;
134→
135→    const handleHit = hitTestViewportHandle(point, handleViewportCandidates, Math.max(SHEET_TOKENS.viewportHandleSize, 6 / viewport.zoom));
136→
137→    if (handleHit) {
138→      editorDispatch({ type: 'SELECT_OBJECT', id: handleHit.viewportId, objectType: 'sheetViewport' });
139→      const selectedViewport = scene.viewports.find((entry) => entry.id === handleHit.viewportId);
140→      dragState.current = {
141→        mode: 'resize',
142→        viewportId: handleHit.viewportId,
143→        handle: handleHit.handle,
144→        origin: point,
145→        initialViewport: selectedViewport || sheet.viewports.find((entry) => entry.id === handleHit.viewportId),
146→      };
147→      capturePointer(event.pointerId);
148→      event.preventDefault();
149→      return;
150→    }
151→
152→    const viewportHit = hitTestViewport(point, scene.viewports);
153→    if (viewportHit) {
154→      editorDispatch({ type: 'SELECT_OBJECT', id: viewportHit.id, objectType: 'sheetViewport' });
155→      dragState.current = {
156→        mode: 'move',
157→        viewportId: viewportHit.id,
158→        origin: point,
159→        initialViewport: viewportHit,
160→      };
161→      capturePointer(event.pointerId);
162→      event.preventDefault();
163→      return;
164→    }
165→
166→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
167→    dragState.current = null;
168→  }, [activePointerId, capturePointer, editorDispatch, getSheetPos, scene, selectedId, selectedType, sheet, viewport.zoom]);
169→
170→  const handlePointerMove = useCallback((event) => {
171→    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
172→
173→    if (isPanning.current) {
174→      const dx = event.clientX - lastPanPos.current.x;
175→      const dy = event.clientY - lastPanPos.current.y;
176→      editorDispatch({ type: 'PAN', dx, dy });
177→      lastPanPos.current = { x: event.clientX, y: event.clientY };
178→      return;
179→    }
180→
181→    if (!dragState.current || !sheet) return;
182→
183→    const point = getSheetPos(event);
184→    const { mode } = dragState.current;
185→
186→    if (mode === 'rotate') {
187→      const { center, initialRotation, startAngle, viewportId } = dragState.current;
188→      const currentAngle = Math.atan2(point.y - center.y, point.x - center.x) * (180 / Math.PI);
189→      let newRotation = initialRotation + (currentAngle - startAngle);
190→      if (event.shiftKey) {
191→        newRotation = Math.round(newRotation / 15) * 15;
192→      }
193→      newRotation = ((newRotation % 360) + 360) % 360;
194→      updateViewport(viewportId, { rotation: newRotation });
195→      return;
196→    }
197→
198→    const { initialViewport, origin, handle, viewportId } = dragState.current;
199→    const dx = point.x - origin.x;
200→    const dy = point.y - origin.y;
201→
202→    if (mode === 'move') {
203→      updateViewport(viewportId, {
204→        x: initialViewport.x + dx,
205→        y: initialViewport.y + dy,
206→      });
207→      return;
208→    }
209→
210→    const next = {
211→      x: initialViewport.x,
212→      y: initialViewport.y,
213→      width: initialViewport.width,
214→      height: initialViewport.height,
215→    };
216→
217→    if (handle.includes('n')) {
218→      next.y = initialViewport.y + dy;
219→      next.height = initialViewport.height - dy;
220→    }
221→    if (handle.includes('s')) {
222→      next.height = initialViewport.height + dy;
223→    }
224→    if (handle.includes('w')) {
225→      next.x = initialViewport.x + dx;
226→      next.width = initialViewport.width - dx;
227→    }
228→    if (handle.includes('e')) {
229→      next.width = initialViewport.width + dx;
230→    }
231→
232→    updateViewport(viewportId, next);
233→  }, [editorDispatch, getSheetPos, sheet, updateViewport]);
234→
235→  const handlePointerUp = useCallback((event) => {
236→    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
237→    isPanning.current = false;
238→    dragState.current = null;
239→    releasePointer(event.pointerId);
240→  }, [releasePointer]);
241→
242→  const handlePointerCancel = useCallback((event) => {
243→    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
244→    isPanning.current = false;
245→    dragState.current = null;
246→    releasePointer(event.pointerId);
247→  }, [releasePointer]);
248→
249→  const handleWheel = useCallback((event) => {
250→    event.preventDefault();
251→    const rect = svgRef.current.getBoundingClientRect();
252→    const mouseX = event.clientX - rect.left;
253→    const mouseY = event.clientY - rect.top;
254→    const direction = event.deltaY < 0 ? 1 : -1;
255→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
256→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
257→    const panX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
258→    const panY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
259→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX, panY });
260→  }, [editorDispatch, viewport]);
261→
262→  useEffect(() => {
263→    const svg = svgRef.current;
264→    if (!svg) return undefined;
265→    const prevent = (event) => event.preventDefault();
266→    svg.addEventListener('contextmenu', prevent);
267→    svg.addEventListener('wheel', handleWheel, { passive: false });
268→    return () => {
269→      svg.removeEventListener('contextmenu', prevent);
270→      svg.removeEventListener('wheel', handleWheel);
271→    };
272→  }, [handleWheel]);
273→
274→  return (
275→    <div className={styles.canvasContainer}>
276→      <svg
277→        ref={svgRef}
278→        className={styles.svg}
279→        style={{ cursor: dragState.current ? 'grabbing' : 'default', touchAction: 'none' }}
280→        onPointerDown={handlePointerDown}
281→        onPointerMove={handlePointerMove}
282→        onPointerUp={handlePointerUp}
283→        onPointerCancel={handlePointerCancel}
284→      >
285→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
