 725→function drawRectToCanvas(context, element) {
 726→  const style = computeStyle(element);
 727→  const x = Number(element.getAttribute('x')) || 0;
 728→  const y = Number(element.getAttribute('y')) || 0;
 729→  const width = Number(element.getAttribute('width')) || 0;
 730→  const height = Number(element.getAttribute('height')) || 0;
 731→
 732→  context.save();
 733→  applyCanvasStyle(context, style);
 734→  context.beginPath();
 735→  context.rect(x, y, width, height);
 736→  fillAndStrokeCanvasPath(context, style);
 737→  context.restore();
 738→}
 739→
 740→function drawLineToCanvas(context, element) {
 741→  const style = computeStyle(element);
 742→  if (!style.stroke || style.strokeWidth <= 0) return;
 743→
 744→  context.save();
 745→  applyCanvasStyle(context, style);
 746→  context.globalAlpha = style.strokeOpacity;
 747→  context.beginPath();
 748→  context.moveTo(Number(element.getAttribute('x1')) || 0, Number(element.getAttribute('y1')) || 0);
 749→  context.lineTo(Number(element.getAttribute('x2')) || 0, Number(element.getAttribute('y2')) || 0);
 750→  context.stroke();
 751→  context.restore();
 752→}
 753→
 754→function drawPolygonToCanvas(context, element, closePath) {
 755→  const style = computeStyle(element);
 756→  const points = parsePoints(element.getAttribute('points') || '');
 757→  if (!points.length) return;
 758→
 759→  context.save();
 760→  applyCanvasStyle(context, style);
 761→  context.beginPath();
 762→  context.moveTo(points[0].x, points[0].y);
 763→  for (let index = 1; index < points.length; index += 1) {
 764→    context.lineTo(points[index].x, points[index].y);
 765→  }
 766→  if (closePath) context.closePath();
 767→  fillAndStrokeCanvasPath(context, style);
 768→  context.restore();
 769→}
 770→
 771→function drawPathToCanvas(context, element) {
 772→  const style = computeStyle(element);
 773→  const commands = parsePathData(element.getAttribute('d') || '');
 774→  if (!commands.length) return;
 775→
 776→  context.save();
 777→  applyCanvasStyle(context, style);
 778→  context.beginPath();
 779→  for (const command of commands) {
 780→    if (command.type === 'M') context.moveTo(command.x, command.y);
 781→    else if (command.type === 'L') context.lineTo(command.x, command.y);
 782→    else if (command.type === 'Z') context.closePath();
 783→  }
 784→  fillAndStrokeCanvasPath(context, style);
 785→  context.restore();
 786→}
 787→
 788→function drawTextToCanvas(context, element) {
 789→  const style = computeStyle(element);
 790→  if (!style.fill) return;
 791→
 792→  context.save();
 793→  context.fillStyle = `rgb(${Math.round(style.fill[0] * 255)}, ${Math.round(style.fill[1] * 255)}, ${Math.round(style.fill[2] * 255)})`;
 794→  context.globalAlpha = style.fillOpacity;
 795→  context.font = `${style.fontWeight} ${style.fontSize}px ${style.fontFamily}`;
 796→  context.textAlign = style.textAnchor === 'middle' ? 'center' : style.textAnchor === 'end' ? 'right' : 'left';
 797→  context.textBaseline = style.dominantBaseline === 'middle' ? 'middle' : 'alphabetic';
 798→
 799→  const lines = getTextLines(element);
 800→  for (const line of lines) {
 801→    context.fillText(line.text, line.x, line.y);
 802→  }
 803→
 804→  context.restore();
 805→}
 806→
 807→function drawImageToCanvas(context, element, imageMap) {
 808→  const href = element.getAttribute('href') || element.getAttributeNS('http://www.w3.org/1999/xlink', 'href');
 809→  const entry = href && imageMap.get(href);
 810→  if (!entry) return;
 811→  const x = Number(element.getAttribute('x')) || 0;
 812→  const y = Number(element.getAttribute('y')) || 0;
 813→  const width = Number(element.getAttribute('width')) || entry.width;
 814→  const height = Number(element.getAttribute('height')) || entry.height;
 815→  context.drawImage(entry.img, x, y, width, height);
 816→}
 817→
 818→function drawElementToCanvas(context, element, imageMap) {
 819→  const tagName = element.tagName.toLowerCase();
 820→  beginCanvasNode(context, element);
 821→
 822→  switch (tagName) {
 823→    case 'svg':
 824→    case 'g':
 825→      [...element.children].forEach((child) => drawElementToCanvas(context, child, imageMap));
 826→      break;
 827→    case 'rect':
 828→      drawRectToCanvas(context, element);
 829→      break;
 830→    case 'line':
 831→      drawLineToCanvas(context, element);
 832→      break;
 833→    case 'polygon':
 834→      drawPolygonToCanvas(context, element, true);
 835→      break;
 836→    case 'polyline':
 837→      drawPolygonToCanvas(context, element, false);
 838→      break;
 839→    case 'path':
 840→      drawPathToCanvas(context, element);
 841→      break;
 842→    case 'text':
 843→      drawTextToCanvas(context, element);
 844→      break;
 845→    case 'image':
 846→      drawImageToCanvas(context, element, imageMap);
 847→      break;
 848→    default:
 849→      [...element.children].forEach((child) => drawElementToCanvas(context, child, imageMap));
 850→      break;
 851→  }
 852→
 853→  endCanvasNode(context);
 854→}
