 870→function renderRect(builder, element) {
 871→  const x = Number(element.getAttribute('x')) || 0;
 872→  const y = Number(element.getAttribute('y')) || 0;
 873→  const width = Number(element.getAttribute('width')) || 0;
 874→  const height = Number(element.getAttribute('height')) || 0;
