451→    case 'truss_detail':
452→      return 'Truss Detail';
453→    case 'roof_plan':
454→      return 'Roof Plan';
455→    case 'roof_drainage':
456→      return 'Roof Drainage';
457→    case 'roof_elevation_front':
458→      return 'Roof Front Elevation';
459→    case 'roof_elevation_rear':
460→      return 'Roof Rear Elevation';
461→    case 'roof_elevation_left':
462→      return 'Roof Left Elevation';
463→    case 'roof_elevation_right':
464→      return 'Roof Right Elevation';
465→    case 'roof_section':
466→      return 'Roof Section';
467→    case 'roof_schedule':
468→      return 'Roof Schedule';
469→    case '3d_preview':
470→      return 'Axonometric View';
471→    case 'section':
