243→function ConstraintsSection({ part, project, dispatch }) {
244→  const [showForm, setShowForm] = useState(false);
245→  const [cType, setCType] = useState('attach_face');
246→  const [targetId, setTargetId] = useState('');
247→  const [srcAnchor, setSrcAnchor] = useState('bottom');
248→  const [tgtAnchor, setTgtAnchor] = useState('top');
249→  const [offset, setOffset] = useState(0);
250→
251→  const constraints = (project.constraints || []).filter(
252→    (c) => c.sourcePartId === part.id || c.targetPartId === part.id
253→  );
254→
255→  const otherParts = project.parts.filter((p) => p.id !== part.id && p.type !== 'dimension');
256→
257→  const handleAddConstraint = () => {
258→    if (!targetId) return;
259→    const constraint = createConstraint({
260→      type: cType,
261→      sourcePartId: part.id,
262→      targetPartId: targetId,
263→      sourceAnchor: srcAnchor,
264→      targetAnchor: tgtAnchor,
