282→                className={styles.constraintDelete}
283→                onClick={() => dispatch({ type: 'CONSTRAINT_DELETE', constraintId: c.id })}
284→                title="Remove constraint"
285→              >
286→                ×
287→              </button>
288→            </div>
289→          );
290→        })}
291→      </div>
292→
293→      {!showForm ? (
294→        <button className={styles.duplicateBtn} onClick={() => setShowForm(true)}>
295→          Add Constraint
296→        </button>
297→      ) : (
298→        <div className={styles.constraintSection}>
299→          <SelectInput label="Type" value={cType} options={CONSTRAINT_TYPES} onChange={setCType} />
300→          <label className={styles.field}>
301→            <span className={styles.fieldLabel}>Target</span>
302→            <select className={styles.selectInput} value={targetId} onChange={(e) => setTargetId(e.target.value)}>
303→              <option value="">Select...</option>
304→              {otherParts.map((p) => (
305→                <option key={p.id} value={p.id}>{p.name} ({p.type})</option>
306→              ))}
307→            </select>
308→          </label>
309→          <SelectInput label="Source Anchor" value={srcAnchor} options={ANCHOR_OPTIONS} onChange={setSrcAnchor} />
310→          <SelectInput label="Target Anchor" value={tgtAnchor} options={ANCHOR_OPTIONS} onChange={setTgtAnchor} />
311→          <NumberInput label="Offset" value={offset} suffix="mm" onChange={setOffset} />
312→          <div style={{ display: 'flex', gap: '4px' }}>
313→            <button className={styles.duplicateBtn} onClick={handleAddConstraint}>Create</button>
314→            <button className={styles.duplicateBtn} onClick={() => setShowForm(false)}>Cancel</button>
315→          </div>
316→        </div>
317→      )}
318→    </div>
319→  );
320→}
