 57→      const newPos = resolved.get(p.id);
 58→      return newPos ? { ...p, position: newPos } : p;
 59→    }),
 60→  };
 61→}
 62→
 63→function updateBoundDimensions(project, updatedPartId) {
 64→  const updatedPart = project.parts.find((p) => p.id === updatedPartId);
 65→  if (!updatedPart) return project;
 66→
 67→  let changed = false;
 68→  const newParts = project.parts.map((p) => {
 69→    if (p.type === 'dimension' && p.boundPartId === updatedPartId) {
 70→      changed = true;
 71→      return updateBoundDimensionEndpoints(p, updatedPart);
 72→    }
 73→    return p;
 74→  });
 75→
 76→  return changed ? { ...project, parts: newParts } : project;
 77→}
 78→
 79→function clonePart(part, idMap) {
 80→  const newId = generateId('part');
 81→  idMap.set(part.id, newId);
 82→  return {
 83→    ...part,
 84→    id: newId,
 85→    name: `${part.name} (copy)`,
 86→    position: {
 87→      ...part.position,
 88→      x: part.position.x + 50,
 89→      y: part.position.y + 50,
 90→    },
 91→  };
 92→}
 93→
 94→function sketchReducer(state, action) {
 95→  switch (action.type) {
 96→    case 'SKETCH_NEW': {
 97→      const newProject = action.project || createSketchProject();
 98→      return {
 99→        project: newProject,
100→        isDirty: false,
101→        savedSnapshot: snapshotSketch(newProject),
102→        history: [],
103→        future: [],
104→      };
105→    }
106→
107→    case 'SKETCH_LOAD': {
108→      const loaded = action.project;
109→      return {
110→        project: loaded,
111→        isDirty: false,
112→        savedSnapshot: snapshotSketch(loaded),
113→        history: [],
114→        future: [],
115→      };
116→    }
117→
118→    case 'PART_ADD': {
119→      const part = sanitizePart(action.part);
120→      let nextProject = {
121→        ...state.project,
122→        updatedAt: new Date().toISOString(),
123→        parts: [...state.project.parts, part],
124→      };
125→      nextProject = applyConstraints(nextProject);
126→      return applyUpdate(state, nextProject);
127→    }
128→
129→    case 'PART_UPDATE': {
130→      let nextProject = {
131→        ...state.project,
132→        updatedAt: new Date().toISOString(),
133→        parts: state.project.parts.map((p) => {
134→          if (p.id !== action.part.id) return p;
135→          const merged = mergePart(p, action.part);
136→          return merged.type === 'dimension' ? merged : sanitizePart(merged);
137→        }),
138→      };
139→      nextProject = applyConstraints(nextProject);
140→      nextProject = updateBoundDimensions(nextProject, action.part.id);
141→      return applyUpdate(state, nextProject);
142→    }
143→
144→    case 'PART_DELETE': {
145→      const partId = action.partId;
146→      // Also remove child parts (cutouts/holes with this parentId)
147→      const childIds = new Set(
148→        state.project.parts.filter((p) => p.parentId === partId).map((p) => p.id)
149→      );
150→      const idsToRemove = new Set([partId, ...childIds]);
151→
152→      // Also remove constraints referencing deleted parts
153→      const constraints = (state.project.constraints || []).filter(
154→        (c) => !idsToRemove.has(c.sourcePartId) && !idsToRemove.has(c.targetPartId)
155→      );
156→
157→      // Also remove dimensions bound to deleted parts
158→      return applyUpdate(state, {
159→        ...state.project,
160→        updatedAt: new Date().toISOString(),
161→        parts: state.project.parts
162→          .filter((p) => !idsToRemove.has(p.id))
163→          .map((p) => {
164→            if (p.type === 'dimension' && p.boundPartId && idsToRemove.has(p.boundPartId)) {
165→              return { ...p, boundPartId: null, boundProperty: null, boundAxis: null };
166→            }
167→            return p;
168→          }),
169→        assemblies: state.project.assemblies.map((asm) => ({
170→          ...asm,
171→          partIds: asm.partIds.filter((id) => !idsToRemove.has(id)),
172→        })),
173→        constraints,
174→      });
175→    }
176→
177→    case 'PART_CLONE': {
178→      const partId = action.partId;
179→      const part = state.project.parts.find((p) => p.id === partId);
180→      if (!part) return state;
181→
182→      const idMap = new Map();
183→      const cloned = clonePart(part, idMap);
184→
185→      // Clone children (cutouts/holes with matching parentId)
186→      const children = state.project.parts.filter((p) => p.parentId === partId);
187→      const clonedChildren = children.map((child) => {
188→        const clonedChild = clonePart(child, idMap);
189→        clonedChild.parentId = cloned.id;
190→        return clonedChild;
191→      });
192→
193→      const newParts = [cloned, ...clonedChildren];
194→
195→      // Add to same assembly if applicable
196→      let assemblies = state.project.assemblies;
197→      if (part.assemblyId) {
198→        assemblies = assemblies.map((asm) => {
199→          if (asm.id === part.assemblyId) {
200→            return {
201→              ...asm,
202→              partIds: [...asm.partIds, ...newParts.map((p) => p.id)],
203→            };
204→          }
205→          return asm;
206→        });
207→        // Set assemblyId on clones
208→        for (const np of newParts) {
209→          np.assemblyId = part.assemblyId;
210→        }
211→      }
212→
213→      return applyUpdate(state, {
214→        ...state.project,
215→        updatedAt: new Date().toISOString(),
216→        parts: [...state.project.parts, ...newParts],
217→        assemblies,
218→      });
219→    }
220→
221→    case 'ASSEMBLY_ADD':
222→      return applyUpdate(state, {
223→        ...state.project,
224→        updatedAt: new Date().toISOString(),
225→        assemblies: [...state.project.assemblies, action.assembly],
226→      });
227→
228→    case 'ASSEMBLY_UPDATE':
229→      return applyUpdate(state, {
230→        ...state.project,
231→        updatedAt: new Date().toISOString(),
232→        assemblies: state.project.assemblies.map((asm) =>
233→          asm.id === action.assembly.id ? { ...asm, ...action.assembly } : asm
234→        ),
235→      });
236→
237→    case 'ASSEMBLY_DELETE': {
238→      const asmId = action.assemblyId;
239→      return applyUpdate(state, {
240→        ...state.project,
241→        updatedAt: new Date().toISOString(),
242→        assemblies: state.project.assemblies.filter((asm) => asm.id !== asmId),
243→        parts: state.project.parts.map((p) =>
244→          p.assemblyId === asmId ? { ...p, assemblyId: null } : p
245→        ),
246→      });
247→    }
248→
249→    case 'ASSEMBLY_ADD_PART': {
250→      const { assemblyId, partId } = action;
251→      return applyUpdate(state, {
