102→function buildPlanSource(floor) {
103→  if (!floor) {
104→    return {
105→      kind: 'empty',
106→      title: 'Plan',
107→      message: 'Missing floor.',
108→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
109→    };
110→  }
111→
112→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
113→
114→  return {
115→    kind: 'plan',
116→    title: `${floor.name} Plan`,
117→    floor,
118→    bounds: geometryBounds,
119→  };
120→}
