122→function sceneBoundsToRenderBounds(scene) {
123→  return {
124→    minX: scene.bounds.minX - VERTICAL_PADDING,
125→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
126→    minY: -scene.bounds.maxZ - TOP_PADDING,
127→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
128→  };
129→}
