277→function buildTrussPlanSource(project, sourceFloorId) {
278→  const floor = resolveProjectFloor(project, sourceFloorId);
279→  const trussSystems = getProjectTrussSystems(project, sourceFloorId);
280→  if (!floor || !trussSystems.length) {
281→    return {
282→      kind: 'empty',
283→      title: 'Truss Plan',
284→      message: 'No truss systems on this floor.',
285→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
286→    };
287→  }
288→
289→  const trussGeometry = buildFloorTrussGeometry(trussSystems);
290→  const floorBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
291→  return {
292→    kind: 'truss_plan',
293→    title: `${floor.name} Truss Plan`,
294→    floor,
295→    trussSystems,
296→    bounds: {
297→      minX: Math.min(floorBounds.minX, trussGeometry.bounds.minX),
298→      maxX: Math.max(floorBounds.maxX, trussGeometry.bounds.maxX),
299→      minY: Math.min(floorBounds.minY, trussGeometry.bounds.minY),
300→      maxY: Math.max(floorBounds.maxY, trussGeometry.bounds.maxY),
301→    },
302→  };
