308→    ? trussSystems.find((trussSystem) => (
309→        (trussSystem.trussInstances || []).some((trussInstance) => trussInstance.id === sourceRefId)
310→      )) || null
311→    : trussSystems[0] || null;
312→  const trussInstanceId = sourceRefId
313→    || trussDetailRef?.trussInstances?.[0]?.id
314→    || null;
315→  if (!trussDetailRef || !trussInstanceId) {
316→    return {
317→      kind: 'empty',
318→      title: 'Truss Detail',
319→      message: 'No truss detail is available for this floor.',
320→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
321→    };
322→  }
323→
324→  const detailScene = buildTrussDetailScene(trussDetailRef, trussInstanceId);
325→  if (!detailScene) {
326→    return {
327→      kind: 'empty',
328→      title: 'Truss Detail',
329→      message: 'No truss detail is available for this floor.',
330→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
