102→export function formatSheetDate(value) {
103→  if (!value) return '';
104→  const date = new Date(value);
105→  if (Number.isNaN(date.getTime())) return String(value);
106→  const year = date.getFullYear();
107→  const month = String(date.getMonth() + 1).padStart(2, '0');
108→  const day = String(date.getDate()).padStart(2, '0');
109→  return `${year}-${month}-${day}`;
110→}
