137→  if (source?.kind === 'roof_section') return 'ROOF SECTION';
138→  if (source?.kind === 'roof_schedule') return 'ROOF SCHEDULE';
139→  if (source?.kind === 'section') return 'BUILDING SECTION';
140→  if (source?.kind === 'elevation') return 'EXTERIOR ELEVATION';
141→  return 'CONSTRUCTION VIEW';
142→}
