144→export function resolveSheetScaleLabel(sheet, viewports = []) {
145→  if (sheet?.scaleMode === 'as_noted') return 'As noted';
146→  if (sheet?.scaleMode === 'per_viewport') return 'As noted';
147→
148→  const explicit = sheet?.scaleLabel?.trim();
149→  if (explicit) return explicit;
150→
151→  const scales = [...new Set(viewports
152→    .filter((viewport) => viewport.source?.kind !== '3d_preview')
153→    .map((viewport) => Math.max(1, Math.round(Number(viewport.scale) || 100))) )];
154→
155→  if (scales.length === 1) return `1:${scales[0]}`;
156→  return 'As noted';
157→}
