 90→function ThreePreviewViewportContent({ source }) {
 91→  const [previewState, setPreviewState] = useState({
 92→    status: 'loading',
 93→    imageUrl: null,
 94→  });
 95→
 96→  useEffect(() => {
 97→    if (!source?.project) {
 98→      setPreviewState({
 99→        status: 'empty',
100→        imageUrl: null,
101→      });
102→      return undefined;
103→    }
104→
105→    let cancelled = false;
106→    setPreviewState({
107→      status: 'loading',
108→      imageUrl: null,
109→    });
110→
111→    renderSheetPreviewImage(source)
112→      .then((result) => {
113→        if (cancelled) return;
114→        setPreviewState(result);
115→      })
116→      .catch((error) => {
117→        if (cancelled) return;
118→        console.error('Failed to render sheet 3D preview:', error);
119→        setPreviewState({
120→          status: 'error',
121→          imageUrl: null,
122→        });
123→      });
124→
125→    return () => { cancelled = true; };
126→  }, [source?.project, source?.project?.updatedAt, source?.activeFloorId]);
127→
128→  const { bounds } = source;
129→  const centerX = (bounds.minX + bounds.maxX) / 2;
130→  const centerY = (bounds.minY + bounds.maxY) / 2;
131→
132→  if (previewState.status !== 'ready' || !previewState.imageUrl) {
133→    const messages = {
134→      loading: 'Rendering 3D preview...',
135→      empty: 'No 3D geometry available.',
136→      error: '3D preview failed to render.',
137→    };
138→
139→    return (
140→      <text
141→        x={centerX}
142→        y={centerY}
143→        textAnchor="middle"
144→        fontSize={400}
145→        fill="#8899aa"
146→        pointerEvents="none"
147→      >
148→        {messages[previewState.status] || messages.loading}
149→      </text>
150→    );
151→  }
152→
153→  return (
154→    <image
155→      href={previewState.imageUrl}
156→      x={bounds.minX}
157→      y={bounds.minY}
158→      width={bounds.maxX - bounds.minX}
159→      height={bounds.maxY - bounds.minY}
160→      preserveAspectRatio="xMidYMid meet"
161→      pointerEvents="none"
162→    />
163→  );
164→}
