 807→function drawImageToCanvas(context, element, imageMap) {
 808→  const href = element.getAttribute('href') || element.getAttributeNS('http://www.w3.org/1999/xlink', 'href');
 809→  const entry = href && imageMap.get(href);
 810→  if (!entry) return;
 811→  const x = Number(element.getAttribute('x')) || 0;
 812→  const y = Number(element.getAttribute('y')) || 0;
 813→  const width = Number(element.getAttribute('width')) || entry.width;
 814→  const height = Number(element.getAttribute('height')) || entry.height;
 815→  context.drawImage(entry.img, x, y, width, height);
 816→}
 817→
 818→function drawElementToCanvas(context, element, imageMap) {
 819→  const tagName = element.tagName.toLowerCase();
 820→  beginCanvasNode(context, element);
 821→
 822→  switch (tagName) {
 823→    case 'svg':
 824→    case 'g':
 825→      [...element.children].forEach((child) => drawElementToCanvas(context, child, imageMap));
 826→      break;
 827→    case 'rect':
 828→      drawRectToCanvas(context, element);
 829→      break;
 830→    case 'line':
 831→      drawLineToCanvas(context, element);
 832→      break;
 833→    case 'polygon':
 834→      drawPolygonToCanvas(context, element, true);
 835→      break;
 836→    case 'polyline':
 837→      drawPolygonToCanvas(context, element, false);
 838→      break;
 839→    case 'path':
 840→      drawPathToCanvas(context, element);
 841→      break;
 842→    case 'text':
 843→      drawTextToCanvas(context, element);
 844→      break;
 845→    case 'image':
 846→      drawImageToCanvas(context, element, imageMap);
 847→      break;
 848→    default:
 849→      [...element.children].forEach((child) => drawElementToCanvas(context, child, imageMap));
 850→      break;
 851→  }
 852→
 853→  endCanvasNode(context);
 854→}
