 886→function renderLine(builder, element) {
 887→  const x1 = Number(element.getAttribute('x1')) || 0;
 888→  const y1 = Number(element.getAttribute('y1')) || 0;
 889→  const x2 = Number(element.getAttribute('x2')) || 0;
