106→export default function SketchSidebar() {
107→  const { project, dispatch, getPartsForAssembly } = useSketch();
108→  const { activeAssemblyId, selectedId, dispatch: editorDispatch } = useSketchEditor();
109→
110→  const [expandedIds, setExpandedIds] = useState(new Set());
111→
112→  const assemblies = project.assemblies || [];
113→  const allParts = project.parts.filter((p) => p.type !== 'dimension');
114→
115→  // Build part tree: group by assembly, then nest children under parents
116→  const toggleExpand = (id) => {
117→    setExpandedIds((prev) => {
118→      const next = new Set(prev);
119→      if (next.has(id)) next.delete(id);
120→      else next.add(id);
121→      return next;
122→    });
123→  };
124→
125→  const handleAddAssembly = () => {
126→    const asm = createAssembly(`Assembly ${assemblies.length + 1}`);
127→    dispatch({ type: 'ASSEMBLY_ADD', assembly: asm });
128→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: asm.id });
129→  };
130→
131→  const handleSelectAssembly = (assemblyId) => {
132→    editorDispatch({
133→      type: 'SET_ACTIVE_ASSEMBLY',
134→      assemblyId: activeAssemblyId === assemblyId ? null : assemblyId,
135→    });
136→  };
137→
138→  const handleDeleteAssembly = (e, assemblyId) => {
139→    e.stopPropagation();
140→    dispatch({ type: 'ASSEMBLY_DELETE', assemblyId });
141→    if (activeAssemblyId === assemblyId) {
142→      editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
143→    }
144→  };
145→
146→  const handleCloneAssembly = (e, assemblyId) => {
147→    e.stopPropagation();
148→    dispatch({ type: 'ASSEMBLY_CLONE', assemblyId });
149→  };
150→
151→  const handleSelectPart = (partId) => {
152→    editorDispatch({ type: 'SELECT_OBJECT', id: partId, objectType: 'part' });
153→  };
154→
155→  const handleDeletePart = (partId) => {
156→    dispatch({ type: 'PART_DELETE', partId });
157→    if (selectedId === partId) {
158→      editorDispatch({ type: 'DESELECT' });
159→    }
160→  };
161→
162→  const handleClonePart = (partId) => {
163→    dispatch({ type: 'PART_CLONE', partId });
164→  };
165→
166→  // Build tree for a given set of parts
167→  function renderPartTree(parts, depth = 0) {
168→    const topLevel = parts.filter((p) => !p.parentId || !parts.some((pp) => pp.id === p.parentId));
169→    return topLevel.map((part) => {
170→      const children = parts.filter((p) => p.parentId === part.id);
171→      return (
172→        <div key={part.id}>
173→          <PartItem
174→            part={part}
175→            isSelected={part.id === selectedId}
176→            depth={depth}
177→            onSelect={handleSelectPart}
178→            onDelete={handleDeletePart}
179→            onClone={handleClonePart}
180→          />
181→          {children.length > 0 && children.map((child) => (
182→            <PartItem
183→              key={child.id}
184→              part={child}
185→              isSelected={child.id === selectedId}
186→              depth={depth + 1}
187→              onSelect={handleSelectPart}
188→              onDelete={handleDeletePart}
189→              onClone={handleClonePart}
190→            />
191→          ))}
192→        </div>
193→      );
194→    });
195→  }
196→
197→  // Unassigned parts: no assemblyId
198→  const unassignedParts = allParts.filter((p) => !p.assemblyId);
199→
200→  return (
201→    <div className={styles.sidebar}>
202→      {/* Assemblies panel */}
203→      <div className={styles.section}>
204→        <div className={styles.sectionHeaderRow}>
205→          <span className={styles.sectionTitle}>Assemblies</span>
206→          <span className={styles.count}>{assemblies.length}</span>
207→          <button className={styles.addBtn} onClick={handleAddAssembly} aria-label="Add Assembly" title="Add Assembly">+</button>
208→        </div>
209→
210→        <div className={styles.layerList}>
211→          {assemblies.map((asm) => {
212→            const isActive = asm.id === activeAssemblyId;
213→            const isExpanded = expandedIds.has(asm.id);
214→            const asmParts = allParts.filter((p) => p.assemblyId === asm.id);
215→            const partCount = asmParts.length;
216→
217→            return (
218→              <div key={asm.id}>
219→                <div
220→                  className={`${styles.layerItem} ${isActive ? styles.layerItemActive : ''}`}
221→                  onClick={() => handleSelectAssembly(asm.id)}
222→                  role="button"
223→                  tabIndex={0}
224→                  onKeyDown={(e) => {
225→                    if (e.key === 'Enter' || e.key === ' ') {
226→                      e.preventDefault();
227→                      handleSelectAssembly(asm.id);
228→                    }
229→                  }}
230→                >
231→                  <div className={styles.layerInfo}>
232→                    <button
233→                      className={styles.expandBtn}
234→                      onClick={(e) => { e.stopPropagation(); toggleExpand(asm.id); }}
235→                      aria-label={isExpanded ? 'Collapse' : 'Expand'}
236→                    >
237→                      <ChevronIcon expanded={isExpanded} />
238→                    </button>
239→                    <AssemblyIcon />
240→                    <span className={styles.layerName}>{asm.name}</span>
241→                    {partCount > 0 && <span className={styles.shapeCount}>{partCount}</span>}
242→                  </div>
243→                  <div className={styles.layerActions}>
244→                    <button
245→                      className={styles.layerActionBtn}
246→                      onClick={(e) => handleCloneAssembly(e, asm.id)}
247→                      aria-label="Duplicate Assembly"
248→                      title="Duplicate Assembly"
249→                    >
250→                      <CloneIcon />
251→                    </button>
252→                    <button
253→                      className={styles.layerActionBtn}
254→                      onClick={(e) => handleDeleteAssembly(e, asm.id)}
255→                      aria-label="Delete Assembly"
256→                      title="Delete Assembly"
257→                    >
258→                      <TrashIcon />
259→                    </button>
260→                  </div>
261→                </div>
262→
263→                {/* Expanded: show nested parts */}
264→                {isExpanded && asmParts.length > 0 && (
265→                  <div className={styles.indent}>
266→                    {renderPartTree(asmParts, 1)}
267→                  </div>
268→                )}
269→              </div>
270→            );
271→          })}
272→        </div>
273→      </div>
274→
275→      {/* Unassigned Parts */}
276→      <div className={styles.section}>
277→        <div className={styles.sectionHeaderRow}>
278→          <span className={styles.sectionTitle}>
279→            Unassigned Parts
280→          </span>
281→          <span className={styles.count}>{unassignedParts.length}</span>
282→        </div>
283→
284→        <div className={styles.layerList}>
285→          {renderPartTree(unassignedParts, 0)}
286→        </div>
287→      </div>
288→    </div>
289→  );
290→}
