 58→export default function SketchCanvas() {
 59→  const svgRef = useRef(null);
 60→  const isPanning = useRef(false);
 61→  const lastPanPos = useRef({ x: 0, y: 0 });
 62→  const spaceHeld = useRef(false);
 63→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 64→
 65→  const { project } = useSketch();
 66→  const {
 67→    activeTool, selectedId, toolState,
 68→    viewport, showGrid, activeView, statusMessage, emptyStateDismissed,
 69→    maximizedPanel,
 70→    dispatch: editorDispatch,
 71→  } = useSketchEditor();
 72→
 73→  const tool = useSketchTool();
 74→
 75→  const getModelPos = useCallback((e) => {
 76→    const rect = svgRef.current.getBoundingClientRect();
 77→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 78→  }, [viewport]);
 79→
 80→  const handleMouseDown = useCallback((e) => {
 81→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 82→      isPanning.current = true;
 83→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 84→      e.preventDefault();
 85→      return;
 86→    }
 87→
 88→    const modelPos = getModelPos(e);
 89→    tool.onMouseDown(modelPos, e, toolState);
 90→  }, [getModelPos, tool, toolState]);
 91→
 92→  const handleMouseMove = useCallback((e) => {
 93→    if (isPanning.current) {
 94→      const dx = e.clientX - lastPanPos.current.x;
 95→      const dy = e.clientY - lastPanPos.current.y;
 96→      editorDispatch({ type: 'PAN', dx, dy });
 97→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 98→      return;
 99→    }
100→
101→    const modelPos = getModelPos(e);
102→    setCursorPos(modelPos);
103→    tool.onMouseMove(modelPos, e, toolState, selectedId);
104→  }, [getModelPos, tool, toolState, selectedId, editorDispatch]);
105→
106→  const handleMouseUp = useCallback((e) => {
107→    if (isPanning.current) {
108→      isPanning.current = false;
109→      return;
110→    }
111→
112→    const modelPos = getModelPos(e);
113→    tool.onMouseUp(modelPos, e, toolState);
114→  }, [getModelPos, tool, toolState]);
115→
116→  const handleDoubleClick = useCallback((e) => {
117→    tool.onDoubleClick?.(getModelPos(e), e, toolState);
118→  }, [getModelPos, tool, toolState]);
119→
120→  const handleWheel = useCallback((e) => {
121→    e.preventDefault();
122→    const rect = svgRef.current.getBoundingClientRect();
123→    const mouseX = e.clientX - rect.left;
124→    const mouseY = e.clientY - rect.top;
125→
126→    const direction = e.deltaY < 0 ? 1 : -1;
127→    const factor = direction > 0 ? SKETCH_ZOOM_FACTOR : 1 / SKETCH_ZOOM_FACTOR;
128→    const newZoom = Math.max(SKETCH_MIN_ZOOM, Math.min(SKETCH_MAX_ZOOM, viewport.zoom * factor));
129→
130→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
131→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
132→
133→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
134→  }, [viewport, editorDispatch]);
135→
136→  const handleResetCenterPoint = useCallback(() => {
137→    const rect = svgRef.current?.getBoundingClientRect();
138→    if (!rect) return;
139→
140→    editorDispatch({
141→      type: 'SET_VIEWPORT',
142→      viewport: {
143→        ...viewport,
144→        panX: rect.width / 2,
145→        panY: rect.height / 2,
146→      },
147→    });
148→  }, [editorDispatch, viewport]);
149→
150→  // Keyboard shortcuts
151→  useEffect(() => {
152→    const handleKeyDown = (e) => {
153→      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;
154→
155→      if (e.key === ' ') {
156→        spaceHeld.current = true;
157→        e.preventDefault();
158→        return;
159→      }
160→
161→      if (e.key === 'Escape') {
162→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
163→        return;
164→      }
165→
166→      if (!e.ctrlKey && !e.metaKey) {
167→        const toolKey = SKETCH_TOOL_SHORTCUTS[e.key.toLowerCase()];
168→        if (toolKey) {
169→          editorDispatch({ type: 'SET_TOOL', tool: toolKey });
170→          return;
171→        }
172→      }
173→
174→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
175→        tool.onKeyDown(e, toolState, selectedId);
176→        return;
177→      }
178→
179→      tool.onKeyDown(e, toolState, selectedId);
180→    };
181→
182→    const handleKeyUp = (e) => {
183→      if (e.key === ' ') {
184→        spaceHeld.current = false;
185→      }
186→    };
187→
188→    window.addEventListener('keydown', handleKeyDown);
189→    window.addEventListener('keyup', handleKeyUp);
190→    return () => {
191→      window.removeEventListener('keydown', handleKeyDown);
192→      window.removeEventListener('keyup', handleKeyUp);
193→    };
194→  }, [editorDispatch, selectedId, tool, toolState]);
195→
196→  // Prevent context menu & attach wheel listener
197→  useEffect(() => {
198→    const svg = svgRef.current;
199→    if (!svg) return;
200→    const prevent = (e) => e.preventDefault();
201→    svg.addEventListener('contextmenu', prevent);
202→    svg.addEventListener('wheel', handleWheel, { passive: false });
203→    return () => {
204→      svg.removeEventListener('contextmenu', prevent);
205→      svg.removeEventListener('wheel', handleWheel);
206→    };
207→  }, [handleWheel]);
208→
209→  // Status message auto-clear
210→  useEffect(() => {
211→    if (!statusMessage) return undefined;
212→    const timer = window.setTimeout(() => {
213→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
214→    }, 2500);
215→    return () => window.clearTimeout(timer);
216→  }, [statusMessage, editorDispatch]);
217→
218→  const cursor = spaceHeld.current ? 'grab' : tool.getCursor(toolState);
219→  const zoomPercent = Math.round(viewport.zoom * 1000);
220→
221→  // Check if project is empty for the empty-state overlay
222→  const hasParts = project.parts.length > 0;
223→  const hasAssemblies = project.assemblies.length > 0;
224→  const showEmptyState = !hasParts && !hasAssemblies && !emptyStateDismissed;
225→
226→  // Split parts from dimensions
227→  const renderParts = project.parts.filter((p) => p.type !== 'dimension');
228→  const dimensions = project.parts.filter((p) => p.type === 'dimension');
229→
230→  // Drag preview for part placement
231→  const drawPreview = toolState.drawing && toolState.startPos && toolState.currentPos
232→    ? {
233→        x: Math.min(toolState.startPos.x, toolState.currentPos.x),
234→        y: Math.min(toolState.startPos.y, toolState.currentPos.y),
235→        width: Math.abs(toolState.currentPos.x - toolState.startPos.x),
236→        height: Math.abs(toolState.currentPos.y - toolState.startPos.y),
237→      }
238→    : null;
239→
240→  // Dimension first-click indicator
241→  const dimFirstClick = activeTool === 'dimension' && toolState.firstPoint;
242→
243→  // Compute XYZ from cursor position using inverse projection
244→  const modelXYZ = viewToModelPosition(cursorPos.x, cursorPos.y, activeView);
245→
246→  return (
247→    <div className={styles.canvasContainer}>
248→      <CompassOverlay className={styles.compassDock} />
249→
250→      <svg
251→        ref={svgRef}
252→        className={styles.svg}
253→        style={{ cursor }}
254→        onPointerDown={handleMouseDown}
255→        onPointerMove={handleMouseMove}
256→        onPointerUp={handleMouseUp}
257→        onDoubleClick={handleDoubleClick}
258→      >
259→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
260→          {showGrid && <GridRenderer />}
261→
262→          {/* Canvas boundary indicator */}
263→          <rect
264→            x={0}
265→            y={0}
266→            width={project.canvasWidth}
267→            height={project.canvasHeight}
268→            fill="none"
269→            stroke="var(--color-border)"
270→            strokeWidth={2}
271→            vectorEffect="non-scaling-stroke"
272→            strokeDasharray="8 4"
273→            style={{ pointerEvents: 'none' }}
274→          />
275→
276→          {/* Rendered parts */}
277→          {renderParts.map((part) => (
278→            <PartRenderer
279→              key={part.id}
280→              part={part}
281→              view={activeView}
282→              isSelected={part.id === selectedId}
283→              zoom={viewport.zoom}
284→            />
285→          ))}
286→
287→          {/* Dimension annotations */}
288→          {dimensions.map((dim) => (
289→            <DimensionRenderer
290→              key={dim.id}
291→              dimension={dim}
292→              view={activeView}
293→              zoom={viewport.zoom}
294→              isSelected={dim.id === selectedId}
295→            />
296→          ))}
297→
298→          {/* Draw preview */}
299→          {drawPreview && (
300→            <rect
301→              x={drawPreview.x}
302→              y={drawPreview.y}
303→              width={drawPreview.width}
304→              height={drawPreview.height}
305→              fill="none"
306→              stroke="var(--color-workspace-sketch, #B8860B)"
307→              strokeWidth={2}
308→              vectorEffect="non-scaling-stroke"
309→              strokeDasharray="6 3"
310→              style={{ pointerEvents: 'none' }}
311→            />
312→          )}
313→
314→          {/* Dimension first-click indicator */}
315→          {dimFirstClick && (
316→            <circle
317→              cx={toolState.firstPoint.x}
318→              cy={toolState.firstPoint.y}
319→              r={5 / viewport.zoom}
320→              fill="var(--color-workspace-sketch, #B8860B)"
321→              style={{ pointerEvents: 'none' }}
322→            />
323→          )}
324→        </g>
325→      </svg>
326→
327→      {/* Empty-state overlay */}
328→      {showEmptyState && <SketchEmptyState />}
329→
330→      {/* Overlay controls */}
331→      <div className={styles.overlayControls}>
332→        <button
333→          type="button"
334→          className={styles.overlayBtn}
335→          onClick={handleResetCenterPoint}
336→          title="Center view"
337→        >
338→          <CenterViewIcon />
339→        </button>
340→        <button
341→          type="button"
342→          className={styles.overlayBtn}
343→          onClick={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'canvas' })}
344→          title={maximizedPanel === 'canvas' ? 'Restore split view' : 'Maximize canvas'}
345→        >
346→          {maximizedPanel === 'canvas' ? <CollapseIcon /> : <ExpandIcon />}
347→        </button>
348→      </div>
349→
350→      {/* Status bar */}
351→      <div className={styles.statusBar} role="status" aria-live="polite">
352→        <span className={styles.statusContext}>{getViewLabel(activeView)}</span>
353→        <span className={styles.statusCoords}>X: {Math.round(modelXYZ.x)} mm</span>
354→        <span className={styles.statusCoords}>Y: {Math.round(modelXYZ.y)} mm</span>
355→        <span className={styles.statusCoords}>Z: {Math.round(modelXYZ.z)} mm</span>
356→        <span className={styles.statusContext}>Zoom: {zoomPercent}%</span>
357→        <span className={styles.statusTool}>{activeTool}</span>
358→      </div>
359→
360→      {/* Toast notifications */}
361→      {statusMessage && (
362→        <div className={styles.toast}>
363→          {statusMessage}
364→          <div className={styles.toastProgress} />
365→        </div>
366→      )}
367→    </div>
368→  );
369→}
